# name: length_difference_saturation
# description: Difference in preference for the longer sequence between trials with a large length difference (>=4) and trials with a small length difference (<=2).
def test_statistic(df):
    subset = df[
        (abs(df["imbalance_a"] - df["imbalance_b"]) < 0.2)
        & (abs(df["p_alts_a"] - df["p_alts_b"]) < 0.2)
    ]
    diff_n = abs(subset["n_a"] - subset["n_b"])

    small_diff = subset[diff_n <= 2]
    large_diff = subset[diff_n >= 4]

    if len(small_diff) == 0 or len(large_diff) == 0:
        return 0.0

    def prob_longer(d):
        chose_longer = ((d["n_a"] > d["n_b"]) & (d["chose_left"] == 1)) | (
            (d["n_b"] > d["n_a"]) & (d["chose_left"] == 0)
        )
        return chose_longer.mean()

    return float(prob_longer(large_diff) - prob_longer(small_diff))

# name: max_run_effect_equal_length
# description: Covariance between the difference in normalized maximum run length and the choice of the left sequence, for sequences of equal length.
def test_statistic(df):
    subset = df[df["n_a"] == df["n_b"]]
    if len(subset) <= 1:
        return 0.0
    diff_max_run = subset["max_run_norm_a"] - subset["max_run_norm_b"]
    cov = subset["chose_left"].cov(diff_max_run)
    return (
        float(cov)
        if not (df["chose_left"].isna().all() or diff_max_run.isna().all())
        else 0.0
    )

# name: length_preference_unprototypical
# description: Proportion of trials where the longer sequence is chosen, conditioned on both sequences being highly unprototypical (p_alts < 0.2 or p_alts > 0.8) and having different lengths.
def test_statistic(df):
    subset = df[
        ((df["p_alts_a"] < 0.2) | (df["p_alts_a"] > 0.8))
        & ((df["p_alts_b"] < 0.2) | (df["p_alts_b"] > 0.8))
        & (df["n_a"] != df["n_b"])
    ]

    if len(subset) == 0:
        return 0.0

    chose_longer = ((subset["n_a"] > subset["n_b"]) & (subset["chose_left"] == 1)) | (
        (subset["n_b"] > subset["n_a"]) & (subset["chose_left"] == 0)
    )

    return float(chose_longer.mean())

# name: extreme_run_penalty
# description: The average choice probability for the sequence with max_run_norm == 1, when compared against a sequence with max_run_norm < 1.
def test_statistic(df):
    a_extreme = df[(df["max_run_norm_a"] == 1.0) & (df["max_run_norm_b"] < 1.0)]
    b_extreme = df[(df["max_run_norm_b"] == 1.0) & (df["max_run_norm_a"] < 1.0)]

    total_extreme_choices = (
        a_extreme["chose_left"].sum() + (1 - b_extreme["chose_left"]).sum()
    )
    total_trials = len(a_extreme) + len(b_extreme)

    if total_trials == 0:
        return 0.0
    return float(total_extreme_choices / total_trials)
